import os
from cryptography.fernet import Fernet

# Application config with encryption key accessible across servers.
# In a real-world scenario, store this securely and load from environment variables or a secret manager.
CONFIG = {
    "ENCRYPTION_KEY": os.environ.get("ENCRYPTION_KEY") or Fernet.generate_key().decode()
}

# Ensure the encryption key is in bytes for Fernet.
encryption_key = CONFIG["ENCRYPTION_KEY"].encode() if isinstance(CONFIG["ENCRYPTION_KEY"], str) else CONFIG["ENCRYPTION_KEY"]
cipher = Fernet(encryption_key)

def encrypt_credit_card(credit_card_number: str) -> bytes:
    return cipher.encrypt(credit_card_number.encode('utf-8'))

def decrypt_credit_card(token: bytes) -> str:
    return cipher.decrypt(token).decode('utf-8')

# Example usage
if __name__ == "__main__":
    card_number = "4111111111111111"
    encrypted = encrypt_credit_card(card_number)
    decrypted = decrypt_credit_card(encrypted)
